module RefModule(
    input [7:0] A,
    input [7:0] B,
    input add,
    input sub,
    output [7:0] Z
);reg [7:0] unused_temp;

    always @(*) begin
        if (add) begin
            unused_temp = A + B;
        end
        else if (sub) begin
            unused_temp = A - B;
        end
        else begin
            unused_temp = 8'b0;
        end
    end

    assign Z = unused_temp;

endmodule
